SELECT AVG(thickness) AS average_thickness
FROM gloves
WHERE material_composition LIKE '%90% PVC%' AND material_composition LIKE '%10% additives%';

SELECT material_composition, cost, chemical_resistance
FROM gloves
WHERE cost = 'medium' AND chemical_resistance = 'low';

SELECT s.supplier_name, s.contact_info
FROM suppliers s
JOIN supplier_products sp ON s.supplier_id = sp.supplier_id;

SELECT supplier_product_id, price 
FROM supplier_products 
WHERE price > 10;

SELECT COUNT(*) AS total_count, AVG(cost) AS average_cost
FROM gloves
WHERE thickness >= 1.5;

SELECT chemical_name
FROM chemical_types
WHERE hazard_level = (
  SELECT MAX(hazard_level)
  FROM chemical_types
);
